-- Check and create driver user with test deliveries
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;

-- Check if driver user exists
SELECT 'Checking driver user...' as Status;
SELECT Id, UserName, Email FROM AspNetUsers WHERE Email = 'driver@autoedge.com';

-- Check driver role assignment
SELECT 'Checking driver role assignment...' as Status;
SELECT u.UserName, r.Name as RoleName 
FROM AspNetUsers u
INNER JOIN AspNetUserRoles ur ON u.Id = ur.UserId
INNER JOIN AspNetRoles r ON ur.RoleId = r.Id
WHERE u.Email = 'driver@autoedge.com';

-- Check existing deliveries
SELECT 'Checking existing deliveries...' as Status;
SELECT COUNT(*) as DeliveryCount FROM VehicleDeliveries;

-- Check deliveries assigned to driver
SELECT 'Checking deliveries assigned to driver...' as Status;
SELECT vd.Id, vd.Status, vd.ScheduledDate, vd.DeliveryAddress, vd.DriverId
FROM VehicleDeliveries vd
INNER JOIN AspNetUsers u ON vd.DriverId = u.Id
WHERE u.Email = 'driver@autoedge.com';

-- If no driver user exists, create one
IF NOT EXISTS (SELECT 1 FROM AspNetUsers WHERE Email = 'driver@autoedge.com')
BEGIN
    PRINT 'Creating driver user...';
    
    DECLARE @DriverUserId NVARCHAR(450) = NEWID();
    DECLARE @DriverRoleId NVARCHAR(450);
    
    -- Get Driver role ID
    SELECT @DriverRoleId = Id FROM AspNetRoles WHERE Name = 'Driver';
    
    -- Create driver user
    INSERT INTO AspNetUsers (Id, UserName, NormalizedUserName, Email, NormalizedEmail, EmailConfirmed, PasswordHash, SecurityStamp, ConcurrencyStamp, PhoneNumber, PhoneNumberConfirmed, TwoFactorEnabled, LockoutEnabled, AccessFailedCount)
    VALUES (
        @DriverUserId,
        'driver@autoedge.com',
        'DRIVER@AUTOEDGE.COM',
        'driver@autoedge.com',
        'DRIVER@AUTOEDGE.COM',
        1,
        '